1	export type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	export type Step = { op: "quote"; items: Item[] };
3	export type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
4	export type ScenarioResult = { results: Array<{ premium: number }> };
5	
6	const PROCESSING_FEE = 5;
7	const FIRST_INSURANCE_RATE = 0.1;
8	const CURSE_SURCHARGE_RATE = 0.5;
9	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
10	const HIGH_ENCHANTMENT_THRESHOLD = 5;
11	const LOYALTY_DISCOUNT_RATE = 0.2;
12	const LOYALTY_THRESHOLD_YEARS = 2;
13	
14	type Customer = { yearsWithMHPCO: number };
15	const COMPONENT_UNIT_BASE = 25;
16	const COMPONENT_BLOCK_SIZE = 3;
17	const COMPONENT_BLOCK_BASE = 60;
18	
19	const MAIN_ITEM_BASE_PREMIUM: Record<string, number> = {
20	  sword: 100,
21	  amulet: 60,
22	  staff: 80,
23	  potion: 40,
24	};
25	
26	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
27	
28	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
29	
30	// A billing group is one main item or one bundle of alike components.
31	// `cursed` only applies to main items.
32	type BillingGroup = { base: number; cursed: boolean; enchantment: number };
33	
34	const componentBundleBase = (count: number): number => {
35	  if (count === COMPONENT_BLOCK_SIZE) return COMPONENT_BLOCK_BASE;
36	  return count * COMPONENT_UNIT_BASE;
37	};
38	
39	const billingGroups = (items: Item[]): BillingGroup[] => {
40	  const groups: BillingGroup[] = [];
41	  const componentCounts = new Map<string, number>();
42	  for (const item of items) {
43	    if (isComponent(item)) {
44	      componentCounts.set(item.type, (componentCounts.get(item.type) ?? 0) + 1);
45	    } else {
46	      groups.push({
47	        base: MAIN_ITEM_BASE_PREMIUM[item.type],
48	        cursed: item.cursed === true,
49	        enchantment: item.enchantment ?? 0,
50	      });
51	    }
52	  }
53	  for (const count of componentCounts.values()) {
54	    groups.push({ base: componentBundleBase(count), cursed: false, enchantment: 0 });
55	  }
56	  return groups;
57	};
58	
59	const groupPremium = ({ base, cursed, enchantment }: BillingGroup): number => {
60	  const curseSurcharge = cursed ? base * CURSE_SURCHARGE_RATE : 0;
61	  const enchantmentSurcharge =
62	    enchantment >= HIGH_ENCHANTMENT_THRESHOLD ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE : 0;
63	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_RATE;
64	  return base + curseSurcharge + enchantmentSurcharge + firstInsuranceSurcharge;
65	};
66	
67	const quotePremium = (items: Item[], customer: Customer): number => {
68	  const groups = billingGroups(items);
69	  const itemsTotal = groups.reduce((sum, g) => sum + groupPremium(g), 0);
70	  const policyBase = groups.reduce((sum, g) => sum + g.base, 0);
71	  const loyaltyDiscount =
72	    customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? policyBase * LOYALTY_DISCOUNT_RATE : 0;
73	  return Math.ceil(itemsTotal - loyaltyDiscount + PROCESSING_FEE);
74	};
75	
76	export const runScenario = (scenario: Scenario): ScenarioResult => {
77	  const results = scenario.steps.map((step) => ({
78	    premium: quotePremium(step.items, scenario.customer),
79	  }));
80	  return { results };
81	};
